func contactSidebarURL(filters models.ContactFilters, saveTarget string) string {
	values := url.Values{}
	if strings.TrimSpace(filters.Query) != "" {
		values.Set("q", strings.TrimSpace(filters.Query))
	}
	if saveTarget != "" {
		values.Set("save_target", saveTarget)
	}
	if filters.View == "table" {
		values.Set("view", "table")
	}
	if encoded := values.Encode(); encoded != "" {
		return "/contacts?" + encoded
	}
	return "/contacts"
}

func contactSidebarAccountName(account models.Account) string {
	if strings.TrimSpace(account.Name) != "" {
		return strings.TrimSpace(account.Name)
	}
	return strings.TrimSpace(account.Email)
}

func contactSidebarAccountVisible(account models.Account) bool {
	provider := strings.TrimSpace(account.ContactSyncProvider)
	return !account.IsDeleting && account.ContactSyncEnabled && (len(account.ContactAddressBooks) > 0 || provider == "gmail" || provider == "outlook")
}

func contactSidebarAccountSectionID(account models.Account) string {
	return "contacts:" + strings.TrimSpace(account.ID)
}

func contactSidebarAccountActive(account models.Account, filters models.ContactFilters) bool {
	target := strings.TrimSpace(filters.SaveTarget)
	if target == "account:"+account.ID {
		return true
	}
	for _, book := range account.ContactAddressBooks {
		if target == "book:"+book.ID {
			return true
		}
	}
	return false
}

func contactSidebarAccountItemName(account models.Account) string {
	switch strings.TrimSpace(account.ContactSyncProvider) {
	case "gmail":
		return "Google Contacts"
	case "outlook":
		return "Outlook Contacts"
	}
	return "Contacts"
}

func contactSidebarBookName(book models.ContactAddressBook) string {
	if strings.TrimSpace(book.Name) != "" {
		return strings.TrimSpace(book.Name)
	}
	return "Address book"
}

